    text_section = ri32(text_section_address);
    put_stabs_r(0, CC2_STABS_SOURCE_FILE, 0, 0,
        ri32(add(text_section, CC2_SECTION_DATA_OFFSET)), text_section,
        section_sym);
    return 0;
